Experiencing this as well. Here is hook I wrote to fix this. I call this at the top level in my `_app.tsx`:

```ts
useCorrectFocusAfterNavigation()
```

```ts
import React from "react";
import { useRouter } from "next/router";

/**
 * There is a known issue with Next.js async route navigations where the focus state can become stale
 * after navigation. When using next/link components, the clicked anchor element can remain focused
 * after the page change, causing focus/active styles to persist incorrectly.
 * 
 * This helper function manages focus state after route changes by:
 * 1. Finding the correct target element that matches the new pathname
 * 2. Explicitly setting focus on that element to ensure the UI state matches the route
 * 
 * This fixes issues where:
 * - Focus would "stick" on previously clicked items after navigation
 * - Active states would be out of sync with the current route
 * - Back/forward navigation would have incorrect focus states
 * 
 * See: https://github.com/vercel/next.js/issues/33060
 */
export const useCorrectFocusAfterNavigation = () => {
  const router = useRouter();

  const focusClickedElement = (pathname: string) => {
    // Only change focus if the URL matches the pathname exactly
    // This prevents us from awkwardly switching focus if we're adjusting non-navigable query params
    const elToFocus = document.querySelector(`[href="${pathname}"]`);
    if (elToFocus) {
      (elToFocus as HTMLElement).focus();
    }
  }

  React.useEffect(() => {
    router.events.on("routeChangeComplete", focusClickedElement)
    return () => {
      router.events.off("routeChangeComplete", focusClickedElement)
    }
  }, [router.events])
}
```

The nice thing about this is that initial page load will still focus the initial element like usual. This only gets triggered on client-side navigation via clicks, URL state updates, router changes, etc. You'd want to be careful with editing URL state programmatically, as that could make this function cause side effects with the focus state.

