```js
// pages/torewrite/_middleware.js
import { NextResponse } from "next/server"

export default function middleware(req) {
  const { pathname } = req.nextUrl
  if (pathname.includes(`/_sites`)) {
    return new Response(null, { status: 404 })
  }

  if (!pathname.includes(".") && !pathname.startsWith("/api")) {
    const hostname = req.headers.get("host")
    const domain = process.env.ROOT_URL ?? "localhost:3000"

    const subdomain =
      hostname === domain ? "main" : hostname.replace(`.${domain}`, "")

    const newPathname = pathname.replace("/torewrite", "")

    const destination = new URL(
      `/_sites/${subdomain}${newPathname}`,
      `http://${domain}`
    )

    return NextResponse.rewrite(destination)
  }
}
