I have found temporary workaround for this issue. Since `react` is not actually needed for middleware to operate I am adding react-mock to final `_middleware` asset with custom webpack plugin.
```js
// customWebpackPlugin.js
const fs = require('fs');

class TextAdditionToFinalAsset {
    constructor(textContent, filePathRegExp) {
        this.textContent = textContent;
        this.filePathRegExp = filePathRegExp;
    }

    apply(compiler) {
        compiler.hooks.assetEmitted.tap('TextAdditionToFinalAsset', (_, { content, targetPath }) => {
            if (targetPath.match(this.filePathRegExp)) {
                const newContent = `${this.textContent}\n${content.toString()}`;
                fs.writeFileSync(targetPath, newContent);
            }
        });
    }
}

module.exports = TextAdditionToFinalAsset;
```

