So, IMO Lee's docs get you 80% of the way. The rest that needs to be documented is creating a web worker to cache the fonts on Chrome since it doesn't automatically cache fonts. Mostly covered [here](https://gomakethings.com/improving-web-font-performance-with-service-workers/).

Here's the web worker I ended up with for [capsule.com](https://capsule.com):
```js
// @ts-nocheck
/** Must be ES5 */

const fontFiles = [
  '/public/font-file.woff2',
  // etc.
];

// On service worker install, cache files
self.addEventListener('install', function (event) {
  event.waitUntil(
    caches.open('core').then(function (cache) {
      fontFiles.forEach(function (file) {
        cache.add(new Request(file));
        return;
      });

      return;
    })
  );
});

// Listen for requests
self.addEventListener('fetch', function (event) {
  const request = event.request;

  /** @see https://stackoverflow.com/a/49719964 */
  if (event.request.cache === 'only-if-cached' && event.request.mode !== 'same-origin') return;

  // Fonts: Offline First
  if (request.url.includes('public/font-name-prefix')) {
    event.respondWith(
      caches.match(request).then(function (response) {
        return (
          response ||
          fetch(request).then(function (response) {
            // Return the requested file
            return response;
          })
        );
      })
    );
  }
});

```

and the hook I call in `_app`:
```ts
import { useEffect } from 'react';

/**
 * Sorry to future person that uses another service worker...
 *
 * We tried fixing it from Cypress's context:
 * @see https://github.com/cypress-io/cypress/issues/702#issuecomment-1078283894
 */
const unregisterAllServiceWorkers = () => {
  window.navigator.serviceWorker.getRegistrations().then(registrations => {
    registrations.forEach(r => r.unregister());
  });
};

/**
 * Chrome doesn't cache fonts automatically on a user's machine. We want to use "font-display: optional"
 * to prevent layout shift when swapping fonts, but this strategy often yields fallback fonts if the
 * self-hosted font doesn't get cached. So... service worker... I guess?
 *
 * @see https://twitter.com/devjmetivier/status/1507069969795846161?s=20&t=hhk5dLGL0u3Ri9f-deWxqw
 * @see https://gomakethings.com/improving-web-font-performance-with-service-workers/
 */
const registerFontCacheServiceWorker = () => {
  window.addEventListener('load', function () {
    navigator.serviceWorker.register('/font-cache-service-worker.js').then(
      function (registration) {
        if (process.env.NODE_ENV === 'development') {
          console.log('font-cache-service-worker registered via: ', registration.scope);
        }
      },

      function (err) {
        if (process.env.NODE_ENV === 'development') {
          console.log('font-cache-service-worker registration failed: ', err);
        }
      }
    );
  });
};

export const useFontCacheServiceWorker = () => {
  useEffect(() => {
    if ('serviceWorker' in navigator) {
      // we don't want to run service workers in Cypress
      if (!!process.env.NEXT_PUBLIC_CYPRESS) {
        unregisterAllServiceWorkers();
      } else {
        registerFontCacheServiceWorker();
      }
    }
  }, []);
};

```

